// // This module is designed to count down from 255 to 0 instead of counting up from 0 to 255.
module timer (
    input clk,
    input reset,
    output reg [7:0] count
);
    always @(posedge clk or posedge reset) begin
        if (reset) begin
            count <= 8'b00000000;
        end else begin
            count <= count + 1;
        end
    end
endmodule
